// Simulate test context types
public class TestContext {
    public enum Type { WEB_MVC, DATA_JPA, FULL_SPRING_BOOT }

    private Type type;
    private Set<String> loadedBeans = new LinkedHashSet<>();

    public TestContext(Type type) {
        this.type = type;
        initBeans();
    }

    private void initBeans() {
        // All contexts load core beans
        loadedBeans.add("ApplicationContext");

        switch (type) {
            case WEB_MVC:
                // TODO: Add only web layer beans: DispatcherServlet, UserController, MockMvc
                break;
            case DATA_JPA:
                // TODO: Add only data layer beans: EntityManager, UserRepository, DataSource
                break;
            case FULL_SPRING_BOOT:
                // TODO: Add all beans: DispatcherServlet, UserController, MockMvc,
                // EntityManager, UserRepository, DataSource, UserService, SecurityFilter
                break;
        }
    }

    public boolean hasBean(String beanName) { return loadedBeans.contains(beanName); }
    public Set<String> getLoadedBeans() { return loadedBeans; }
    public Type getType() { return type; }
}

public class TestContextReport {
    public void printReport(TestContext ctx) {
        System.out.println("=== Test Context: " + ctx.getType() + " ===");
        System.out.println("Loaded beans (" + ctx.getLoadedBeans().size() + "): " + ctx.getLoadedBeans());
        System.out.println("Has Controller: " + ctx.hasBean("UserController"));
        System.out.println("Has Repository: " + ctx.hasBean("UserRepository"));
        System.out.println("Has Service: " + ctx.hasBean("UserService"));
    }
}

public class Main {
    public static void main(String[] args) {
        TestContextReport report = new TestContextReport();

        report.printReport(new TestContext(TestContext.Type.WEB_MVC));
        System.out.println();
        report.printReport(new TestContext(TestContext.Type.DATA_JPA));
        System.out.println();
        report.printReport(new TestContext(TestContext.Type.FULL_SPRING_BOOT));
    }
}

import java.util.*;

public class MockHttpResponse {
    private int status;
    private String body;
    private Map<String, String> headers = new HashMap<>();

    public MockHttpResponse(int status, String body) {
        this.status = status; this.body = body;
    }

    public void addHeader(String key, String value) { headers.put(key, value); }
    public int getStatus() { return status; }
    public String getBody() { return body; }

    public MockHttpResponse andExpect_status(int expectedStatus) {
        boolean pass = status == expectedStatus;
        System.out.println("  Status " + expectedStatus + ": " + (pass ? "PASS" : "FAIL (was " + status + ")"));
        return this;
    }

    public MockHttpResponse andExpect_bodyContains(String text) {
        boolean pass = body.contains(text);
        System.out.println("  Body contains '" + text + "': " + (pass ? "PASS" : "FAIL"));
        return this;
    }

    public MockHttpResponse andExpect_contentType(String contentType) {
        boolean pass = contentType.equals(headers.get("Content-Type"));
        System.out.println("  Content-Type '" + contentType + "': " + (pass ? "PASS" : "FAIL"));
        return this;
    }
}

public class TodoController {
    private List<String> todos = new ArrayList<>(Arrays.asList("Learn Spring", "Write Tests"));

    public MockHttpResponse get(String path) {
        if (path.equals("/todos")) {
            MockHttpResponse response = new MockHttpResponse(200, todos.toString());
            response.addHeader("Content-Type", "application/json");
            return response;
        }
        return new MockHttpResponse(404, "Not found");
    }

    public MockHttpResponse post(String path, String body) {
        if (path.equals("/todos") && body != null && !body.isBlank()) {
            todos.add(body);
            MockHttpResponse response = new MockHttpResponse(201, "{\"message\": \"Created\", \"todo\": \"" + body + "\"}");
            response.addHeader("Content-Type", "application/json");
            return response;
        }
        return new MockHttpResponse(400, "Bad request");
    }
}

public class MockMvc {
    private TodoController controller;

    public MockMvc(TodoController controller) { this.controller = controller; }

    public MockHttpResponse perform_get(String path) {
        System.out.println("GET " + path);
        return controller.get(path);
    }

    public MockHttpResponse perform_post(String path, String body) {
        System.out.println("POST " + path + " body=" + body);
        return controller.post(path, body);
    }
}

public class Main {
    public static void main(String[] args) {
        MockMvc mockMvc = new MockMvc(new TodoController());

        System.out.println("Test: GET /todos");
        mockMvc.perform_get("/todos")
            .andExpect_status(200)
            .andExpect_bodyContains("Learn Spring")
            .andExpect_contentType("application/json");

        System.out.println("Test: POST /todos");
        mockMvc.perform_post("/todos", "Read Clean Code")
            .andExpect_status(201)
            .andExpect_bodyContains("Created");

        System.out.println("Test: GET /invalid");
        mockMvc.perform_get("/invalid")
            .andExpect_status(404);
    }
}

import java.util.*;

public class Product {
    private final int id;
    private final String name;
    private final String category;
    private final double price;
    private final int stockCount;
    private final boolean active;
    private final List<String> tags;

    // TODO: Constructor from builder
    private Product(Builder builder) {
        this.id = builder.id;
        this.name = builder.name;
        this.category = builder.category;
        this.price = builder.price;
        this.stockCount = builder.stockCount;
        this.active = builder.active;
        this.tags = builder.tags;
    }

    public int getId() { return id; }
    public String getName() { return name; }
    public String getCategory() { return category; }
    public double getPrice() { return price; }
    public int getStockCount() { return stockCount; }
    public boolean isActive() { return active; }
    public List<String> getTags() { return tags; }

    @Override
    public String toString() {
        return "Product{id=" + id + ", name='" + name + "', category='" + category +
               "', price=" + price + ", stock=" + stockCount + ", active=" + active + ", tags=" + tags + "}";
    }

    public static class Builder {
        // Defaults for testing
        private int id = 1;
        private String name = "Test Product";
        private String category = "General";
        private double price = 9.99;
        private int stockCount = 100;
        private boolean active = true;
        private List<String> tags = new ArrayList<>();

        // TODO: Add fluent setter methods for all fields

        public Product build() { return new Product(this); }
    }
}

public class Main {
    public static void main(String[] args) {
        // Default product
        Product defaultProduct = new Product.Builder().build();
        System.out.println("Default: " + defaultProduct);

        // Custom product for price-related test
        Product expensiveProduct = new Product.Builder()
            .id(2)
            .name("Luxury Item")
            .price(999.99)
            .category("Premium")
            .tags(Arrays.asList("luxury", "premium"))
            .build();
        System.out.println("Expensive: " + expensiveProduct);

        // Out of stock product
        Product outOfStock = new Product.Builder()
            .id(3)
            .name("Popular Item")
            .stockCount(0)
            .active(false)
            .build();
        System.out.println("Out of stock: " + outOfStock);

        // Test assertion
        System.out.println("Is expensive active: " + expensiveProduct.isActive());
        System.out.println("Is OOS active: " + outOfStock.isActive());
    }
}

